  @use call vm:setTemperSlot  @ 18,28,37,47,55
  @use call cm:getAt  @ 19,20,21,29,30,38,39,46,48,56,70,71,78,80,89,97,106,120,121
  @use call vm:setSwingSlot  @ 68,79,88,104
